import{_ as o,o as a,c as i,a2 as t}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"배포 경로 변경 — Research","description":"","frontmatter":{"title":"배포 경로 변경 — Research","feature_id":"014","date":"2026-06-03T00:00:00.000Z"},"headers":[],"relativePath":"specs/014-deploy-root-domain/research.md","filePath":"specs/014-deploy-root-domain/research.md","lastUpdated":null}'),s={name:"specs/014-deploy-root-domain/research.md"};function r(l,e,n,c,d,g){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="research-배포-경로-변경-—-루트-도메인-자동배포" tabindex="-1">Research: 배포 경로 변경 — 루트 도메인 자동배포 <a class="header-anchor" href="#research-배포-경로-변경-—-루트-도메인-자동배포" aria-label="Permalink to &quot;Research: 배포 경로 변경 — 루트 도메인 자동배포&quot;">​</a></h1><p>Phase 0 조사. 스펙 Clarifications(2026-06-03)로 핵심 결정은 확정됐고, 여기서는 구현 방법(도구·설정)의 근거를 정리한다.</p><h2 id="d1-루트-게시-사용자-페이지-저장소-필요" tabindex="-1">D1. 루트 게시 = 사용자 페이지 저장소 필요 <a class="header-anchor" href="#d1-루트-게시-사용자-페이지-저장소-필요" aria-label="Permalink to &quot;D1. 루트 게시 = 사용자 페이지 저장소 필요&quot;">​</a></h2><ul><li><strong>Decision</strong>: 사이트를 <code>coffeeman1/coffeeman1.github.io</code> 저장소에서 게시한다.</li><li><strong>Rationale</strong>: GitHub Pages 에서 프로젝트 저장소(<code>coffeeman1/blog</code>)는 <code>coffeeman1.github.io/blog/</code> 하위 경로로만 게시된다. 루트 <code>coffeeman1.github.io/</code> 는 <strong>사용자 페이지</strong> 전용이며, 반드시 <code>&lt;user&gt;.github.io</code> 라는 이름의 저장소에서만 서빙된다.</li><li><strong>Alternatives considered</strong>: <ul><li>커스텀 도메인(CNAME)으로 루트화 → 스펙에서 명시적으로 제외(도메인 미도입).</li><li><code>blog</code> 저장소를 <code>coffeeman1.github.io</code> 로 rename → 단일 저장소지만 SDD 소스 구조·CI·이슈/PR 히스토리가 게시 저장소와 뒤섞이고, 옛 Hexo 저장소와 충돌 소지. 스펙 Q1=A(소스/게시 분리)로 기각.</li></ul></li></ul><h2 id="d2-크로스-레포-배포-도구" tabindex="-1">D2. 크로스-레포 배포 도구 <a class="header-anchor" href="#d2-크로스-레포-배포-도구" aria-label="Permalink to &quot;D2. 크로스-레포 배포 도구&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>peaceiris/actions-gh-pages@v4</code> 의 <code>external_repository</code> 사용.</li><li><strong>Rationale</strong>: 빌드 산출물 디렉터리를 타 저장소 브랜치로 푸시하는 표준 액션. <code>.nojekyll</code> 자동 생성, <code>force_orphan</code> 으로 단일 커밋 대체 지원, 배포키/PAT 양쪽 인증 지원. 추가 스크립트 없이 선언적으로 구성 가능.</li><li><strong>Alternatives considered</strong>: <ul><li>수동 <code>git clone/commit/push</code> 스텝 → 유연하나 인증·<code>.nojekyll</code>·정리 로직을 직접 관리해야 함. 유지보수 부담으로 기각.</li><li><code>JamesIves/github-pages-deploy-action</code> → 동등 기능. 생태계 사용성·문서 측면에서 peaceiris 채택(택1 문제, 동률이면 기존 관례 없으니 peaceiris).</li><li>GitHub Pages 네이티브 액션(<code>deploy-pages</code>) → <strong>동일 저장소</strong> 전용이라 크로스-레포 불가. 기각(현재 <code>/blog/</code> 게시가 바로 이 방식).</li></ul></li></ul><h2 id="d3-인증-방식-—-ssh-배포키-vs-pat" tabindex="-1">D3. 인증 방식 — SSH 배포키 vs PAT <a class="header-anchor" href="#d3-인증-방식-—-ssh-배포키-vs-pat" aria-label="Permalink to &quot;D3. 인증 방식 — SSH 배포키 vs PAT&quot;">​</a></h2><ul><li><strong>Decision</strong>: SSH 배포키(키쌍) — 공개키는 게시 저장소 Deploy key(write), 개인키는 소스 저장소 Actions secret <code>ACTIONS_DEPLOY_KEY</code>.</li><li><strong>Rationale</strong>: 배포키는 <strong>해당 게시 저장소 한 곳에만</strong> 쓰기 권한을 부여해 최소 권한 원칙에 맞는다. PAT 는 계정 전체 저장소에 광범위 권한이 부여돼 유출 영향이 크다.</li><li><strong>Alternatives considered</strong>: <ul><li>Fine-grained PAT(단일 저장소 한정) → 가능하나 만료·갱신 관리 필요. 배포키가 더 단순·안전.</li><li><code>GITHUB_TOKEN</code> → 기본 토큰은 <strong>현재 저장소</strong> 범위라 크로스-레포 푸시 불가.</li></ul></li></ul><h2 id="d4-기존-루트-콘텐츠-대체-방식" tabindex="-1">D4. 기존 루트 콘텐츠 대체 방식 <a class="header-anchor" href="#d4-기존-루트-콘텐츠-대체-방식" aria-label="Permalink to &quot;D4. 기존 루트 콘텐츠 대체 방식&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>force_orphan: true</code> 로 게시 브랜치를 단일 커밋으로 덮어쓴다.</li><li><strong>Rationale</strong>: 스펙 Q3=A(완전 대체). orphan 푸시는 옛 Hexo 산출물을 남기지 않고 깨끗이 교체하며, 게시 브랜치 히스토리 비대화도 막는다. 옛 Hexo 본문은 <code>../coffeeman1-main</code> 원본 + <code>/blog-archive/</code> 임포트로 이미 보존됨.</li><li><strong>Alternatives considered</strong>: <ul><li>비-orphan 누적 푸시 → 옛 파일 잔존·히스토리 누적. 대체 목적에 부적합.</li></ul></li></ul><h2 id="d5-게시-저장소-pages-빌드-모드" tabindex="-1">D5. 게시 저장소 Pages 빌드 모드 <a class="header-anchor" href="#d5-게시-저장소-pages-빌드-모드" aria-label="Permalink to &quot;D5. 게시 저장소 Pages 빌드 모드&quot;">​</a></h2><ul><li><strong>Decision</strong>: 게시 저장소 Settings → Pages → <strong>Deploy from a branch</strong>, 브랜치=게시 브랜치(<code>main</code>), 폴더=<code>/ (root)</code>.</li><li><strong>Rationale</strong>: 우리가 빌드한 <strong>정적 산출물</strong>을 브랜치로 푸시하므로, Pages 가 그 브랜치 루트를 그대로 서빙해야 한다. &quot;GitHub Actions&quot; 모드면 푸시된 브랜치를 게시하지 않으므로 부적합.</li><li><strong>Alternatives considered</strong>: &quot;GitHub Actions&quot; 빌드 모드 → 게시 저장소에서 다시 빌드 파이프라인을 둬야 함. 이중 빌드라 기각.</li></ul><h2 id="d6-base-변경-영향-범위" tabindex="-1">D6. <code>base</code> 변경 영향 범위 <a class="header-anchor" href="#d6-base-변경-영향-범위" aria-label="Permalink to &quot;D6. `base` 변경 영향 범위&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>blog/.vitepress/config.mts</code> 의 <code>base</code> 만 <code>&#39;/blog/&#39;</code> → <code>&#39;/&#39;</code>.</li><li><strong>Rationale</strong>: 저장소 콘텐츠의 내부 링크는 모두 루트 절대경로이며 VitePress 가 base 를 자동 prefix 한다. 코드 grep 결과 실제 base 의존 지점은 config 한 곳뿐. <code>/blog-archive/blog/...</code> 는 콘텐츠 섹션 경로이지 배포 base 가 아니다.</li><li><strong>부수 발견(비차단)</strong>: <code>blog/skills-talk/worklog/index.md</code> 등에 옛 공개 URL (<code>coffeeman1.github.io/blog/...</code>)을 <strong>설명 텍스트</strong>로 적은 곳이 있다. 링크가 아니라 빌드를 깨지 않으나, 정확성 위해 갱신 권장.</li></ul><h2 id="d7-옛-blog-종료" tabindex="-1">D7. 옛 <code>/blog/</code> 종료 <a class="header-anchor" href="#d7-옛-blog-종료" aria-label="Permalink to &quot;D7. 옛 `/blog/` 종료&quot;">​</a></h2><ul><li><strong>Decision</strong>: 워크플로에서 자체 Pages 배포 제거 → 갱신 중단. 완전 404 는 <code>blog</code> 저장소 Pages <strong>Disable</strong>(수동, 선택).</li><li><strong>Rationale</strong>: 스펙 Q2=C(옛 주소 404 허용, 리다이렉트 없음). 추가 구현 불필요.</li></ul>',16)])])}const b=o(s,[["render",r]]);export{u as __pageData,b as default};
